function SubscribeCheckout({ tier, creator, onComplete }) {
  const { div, h2, h3, p, span, label, form, input } = tags;
  const [billingCycle, setBillingCycle] = createSignal('monthly');
  const [promoCode, setPromoCode] = createSignal('');
  const [promoApplied, setPromoApplied] = createSignal(null);
  const [processing, setProcessing] = createSignal(false);
  const [termsAccepted, setTermsAccepted] = createSignal(false);

  const price = billingCycle() === 'yearly' ? tier.yearlyPrice : tier.monthlyPrice;
  const discount = promoApplied()?.percent || 0;
  const total = price * (1 - discount / 100);

  const applyPromo = () => {
    if (promoCode().toLowerCase() === 'welcome20') {
      setPromoApplied({ code: 'WELCOME20', percent: 20 });
    }
  };

  const handleSubmit = async () => {
    setProcessing(true);
    await new Promise(r => setTimeout(r, 2000));
    setProcessing(false);
    onComplete?.();
  };

  return div({ class: css('_grid _gc1 _lg:gc2 _gap8 _maxw[960px] _mx[auto] _py8 _px4') },
    div({ class: css('_flex _col _gap6') },
      div({},
        h2({ class: css('_heading3 _mb2') }, 'Subscribe to ', creator.name),
        p({ class: css('_fgmuted') }, 'You\'re subscribing to the ', tier.name, ' tier')
      ),
      Card({ class: css('studio-card _p6') },
        h3({ class: css('_heading5 _mb4') }, 'Billing Cycle'),
        div({ class: css('_grid _gc2 _gap4') },
          div({
            class: css(`_p4 _r3 _border _cursor[pointer] _trans ${billingCycle() === 'monthly' ? '_borderPrimary _bgPrimary/5' : '_bordermuted'}`),
            onclick: () => setBillingCycle('monthly')
          },
            div({ class: css('_flex _jcsb _aic') },
              div({},
                span({ class: css('_fontmedium') }, 'Monthly'),
                p({ class: css('_textsm _fgmuted') }, 'Billed monthly')
              ),
              Radio({ checked: billingCycle() === 'monthly' })
            ),
            p({ class: css('_heading4 _mt2') }, '$', tier.monthlyPrice, '/mo')
          ),
          div({
            class: css(`_p4 _r3 _border _cursor[pointer] _trans ${billingCycle() === 'yearly' ? '_borderPrimary _bgPrimary/5' : '_bordermuted'}`),
            onclick: () => setBillingCycle('yearly')
          },
            div({ class: css('_flex _jcsb _aic') },
              div({},
                span({ class: css('_fontmedium') }, 'Yearly'),
                Badge({ variant: 'default', size: 'xs', class: css('_ml2') }, 'Save 20%')
              ),
              Radio({ checked: billingCycle() === 'yearly' })
            ),
            p({ class: css('_heading4 _mt2') }, '$', tier.yearlyPrice, '/yr')
          )
        )
      ),
      Card({ class: css('studio-card _p6') },
        h3({ class: css('_heading5 _mb4') }, 'Payment Method'),
        div({ class: css('_flex _col _gap4') },
          div({ class: css('_flex _col _gap2') },
            label({ class: css('_textsm _fontmedium') }, 'Card Number'),
            div({ class: css('studio-input _flex _aic _p3 _r2') },
              icon('credit-card', { size: '18', class: css('_fgmuted _mr2') }),
              input({ type: 'text', placeholder: '1234 5678 9012 3456', class: css('_flex1 _outline0 _bgTransparent') })
            )
          ),
          div({ class: css('_grid _gc2 _gap4') },
            div({ class: css('_flex _col _gap2') },
              label({ class: css('_textsm _fontmedium') }, 'Expiry'),
              Input({ placeholder: 'MM / YY' })
            ),
            div({ class: css('_flex _col _gap2') },
              label({ class: css('_textsm _fontmedium') }, 'CVC'),
              Input({ placeholder: '123' })
            )
          )
        ),
        div({ class: css('_flex _gap2 _mt4 _pt4 _borderT') },
          Button({ variant: 'outline', size: 'sm', class: css('_flex _aic _gap2') },
            icon('credit-card', { size: '16' }), 'Apple Pay'
          ),
          Button({ variant: 'outline', size: 'sm', class: css('_flex _aic _gap2') },
            icon('credit-card', { size: '16' }), 'Google Pay'
          )
        )
      ),
      div({ class: css('_flex _col _gap2') },
        label({ class: css('_textsm _fontmedium') }, 'Promo Code'),
        div({ class: css('_flex _gap2') },
          Input({ value: promoCode(), onchange: (e) => setPromoCode(e.target.value), placeholder: 'Enter code', class: css('_flex1') }),
          Button({ variant: 'outline', onclick: applyPromo }, 'Apply')
        ),
        promoApplied() ? div({ class: css('_flex _aic _gap2 _textsm _fgSuccess') },
          icon('check-circle', { size: '14' }), promoApplied().code, ' applied - ', promoApplied().percent, '% off'
        ) : null
      )
    ),
    div({ class: css('_flex _col _gap4') },
      Card({ class: css('studio-card _p6 _sticky _top4') },
        h3({ class: css('_heading5 _mb4') }, 'Order Summary'),
        div({ class: css('_flex _aic _gap4 _pb4 _borderB _mb4') },
          div({ class: css('_w12 _h12 _r2 _bgPrimary/10 _flex _center') },
            icon('crown', { class: css('_fgPrimary') })
          ),
          div({ class: css('_flex1') },
            span({ class: css('_fontmedium') }, tier.name, ' Tier'),
            p({ class: css('_textsm _fgmuted') }, creator.name)
          )
        ),
        div({ class: css('_flex _col _gap2 _pb4 _borderB _mb4') },
          div({ class: css('_flex _jcsb _textsm') },
            span({ class: css('_fgmuted') }, 'Subtotal'),
            span({}, '$', price.toFixed(2))
          ),
          promoApplied() ? div({ class: css('_flex _jcsb _textsm _fgSuccess') },
            span({}, 'Discount (', promoApplied().percent, '%)'),
            span({}, '-$', (price * promoApplied().percent / 100).toFixed(2))
          ) : null
        ),
        div({ class: css('_flex _jcsb _fontmedium _mb6') },
          span({}, 'Total'),
          span({ class: css('_heading4') }, '$', total.toFixed(2))
        ),
        div({ class: css('_flex _aic _gap2 _mb4') },
          input({ type: 'checkbox', checked: termsAccepted(), onchange: (e) => setTermsAccepted(e.target.checked) }),
          span({ class: css('_textsm _fgmuted') }, 'I agree to the terms of service and privacy policy')
        ),
        Button({
          variant: 'primary',
          size: 'lg',
          class: css('_wfull studio-glow'),
          disabled: !termsAccepted() || processing(),
          onclick: handleSubmit
        },
          processing() ? 'Processing...' : 'Subscribe for $' + total.toFixed(2) + (billingCycle() === 'yearly' ? '/yr' : '/mo')
        ),
        p({ class: css('_textsm _fgmuted _tc _mt4 _flex _aic _jcc _gap1') },
          icon('lock', { size: '12' }), 'Secure checkout powered by Stripe'
        )
      )
    )
  );
}

