function PurchaseCheckout({ product, onComplete }) {
  const { div, h2, h3, p, span, img } = tags;
  const [processing, setProcessing] = createSignal(false);

  const handlePurchase = async () => {
    setProcessing(true);
    await new Promise(r => setTimeout(r, 2000));
    setProcessing(false);
    onComplete?.();
  };

  return div({ class: css('_grid _gc1 _lg:gc2 _gap8 _maxw[960px] _mx[auto] _py8 _px4') },
    Card({ class: css('studio-card _p6') },
      h3({ class: css('_heading5 _mb4') }, 'Payment'),
      div({ class: css('_flex _col _gap4') },
        Input({ placeholder: 'Card number' }),
        div({ class: css('_grid _gc2 _gap4') },
          Input({ placeholder: 'MM / YY' }),
          Input({ placeholder: 'CVC' })
        )
      )
    ),
    Card({ class: css('studio-card _p6') },
      h3({ class: css('_heading5 _mb4') }, 'You\'re buying'),
      div({ class: css('_flex _gap4 _mb4') },
        product.thumbnail ? img({ src: product.thumbnail, class: css('_w20 _h14 _r2 _objcover') }) : null,
        div({},
          h2({ class: css('_fontmedium') }, product.title),
          p({ class: css('_textsm _fgmuted') }, product.creator)
        )
      ),
      div({ class: css('_flex _jcsb _fontmedium _py4 _borderT _borderB _mb4') },
        span({}, 'Total'),
        span({ class: css('_heading4') }, '$', product.price)
      ),
      Button({ variant: 'primary', size: 'lg', class: css('_wfull'), disabled: processing(), onclick: handlePurchase },
        processing() ? 'Processing...' : 'Buy Now'
      )
    )
  );
}

