function UpgradeCheckout({ currentTier, newTier, onComplete }) {
  const { div, h2, p, span } = tags;
  const proratedAmount = newTier.monthlyPrice - currentTier.monthlyPrice;

  return div({ class: css('_flex _col _gap6 _maxw[480px] _mx[auto] _py8 _px4') },
    h2({ class: css('_heading3 _tc') }, 'Upgrade to ', newTier.name),
    Card({ class: css('studio-card _p6') },
      div({ class: css('_flex _jcsb _aic _pb4 _borderB _mb4') },
        div({},
          p({ class: css('_textsm _fgmuted') }, 'Current'),
          span({ class: css('_fontmedium') }, currentTier.name)
        ),
        icon('arrow-right', { class: css('_fgmuted') }),
        div({ class: css('_tr') },
          p({ class: css('_textsm _fgmuted') }, 'New'),
          span({ class: css('_fontmedium _fgPrimary') }, newTier.name)
        )
      ),
      p({ class: css('_textsm _fgmuted _mb4') }, 'You\'ll be charged the prorated difference for this billing period.'),
      div({ class: css('_flex _jcsb _fontmedium') },
        span({}, 'Amount due today'),
        span({ class: css('_heading4') }, '$', proratedAmount.toFixed(2))
      )
    ),
    Button({ variant: 'primary', size: 'lg', class: css('_wfull studio-glow'), onclick: onComplete },
      'Confirm Upgrade'
    )
  );
}

